import { sxEndpoint } from './endpoint';
import type {
  CreateProductionOrderDto,
  UpdateProductionOrderDto,
  ProductionOrderFilter,
  CreateBomDto,
  UpdateBomDto,
  BomFilter,
  CreateProductionStageDto,
  UpdateProductionStageDto,
  StageTrackingFilter,
  StageFilter,
} from './models';

export const sxService = {
  getProductionOrders: sxEndpoint.getProductionOrders,
  getProductionOrder:  sxEndpoint.getProductionOrder,
  createProductionOrder: (dto: CreateProductionOrderDto) => sxEndpoint.createProductionOrder(dto),
  updateProductionOrder: (id: string, dto: UpdateProductionOrderDto) =>
    sxEndpoint.updateProductionOrder(id, dto),
  releaseProductionOrder: sxEndpoint.releaseProductionOrder,
  completeProductionOrder: sxEndpoint.completeProductionOrder,

  getBoms: (filter?: BomFilter) => sxEndpoint.getBoms(filter),
  getBom: sxEndpoint.getBom,
  createBom: (dto: CreateBomDto) => sxEndpoint.createBom(dto),
  updateBom: (id: string, dto: UpdateBomDto) => sxEndpoint.updateBom(id, dto),

  getStages: (filter?: StageFilter) => sxEndpoint.getStages(filter),
  createStage: (dto: CreateProductionStageDto) => sxEndpoint.createStage(dto),
  updateStage: (id: string, dto: UpdateProductionStageDto) => sxEndpoint.updateStage(id, dto),

  getStageTracking: (filter?: StageTrackingFilter) => sxEndpoint.getStageTracking(filter),
  qcApproveStageTracking: sxEndpoint.qcApproveStageTracking,
  qcRejectStageTracking: sxEndpoint.qcRejectStageTracking,
};
